    21→#include "iree/compiler/Codegen/LLVMCPU/Passes.h.inc"
    22→
    23→namespace {
    24→struct LLVMCPUVerifyVectorSizeLegalityPass
    25→    : impl::LLVMCPUVerifyVectorSizeLegalityPassBase<
    26→          LLVMCPUVerifyVectorSizeLegalityPass> {
    27→  using impl::LLVMCPUVerifyVectorSizeLegalityPassBase<
    28→      LLVMCPUVerifyVectorSizeLegalityPass>::
    29→      LLVMCPUVerifyVectorSizeLegalityPassBase;
    30→  explicit LLVMCPUVerifyVectorSizeLegalityPass(
    31→      int64_t maxAllowedNumberOfNativeVectors) {
    32→    this->maxAllowedNumberOfNativeVectors = maxAllowedNumberOfNativeVectors;
    33→  }
    34→
    35→  void runOnOperation() override;
    36→};
    37→} // namespace
    38→
    39→static int64_t getTotalSizeInBytes(Type elemType, ArrayRef<int64_t> shape) {
    40→  // We can't query bitwidth for some types (e.g., index type). For those
    41→  // cases, we assume that they are 64 bits because most of modern systems are
    42→  // 64-bit.
    43→  int64_t elemBitWidth = 64;
    44→  if (elemType.isIntOrFloat()) {
    45→    elemBitWidth = elemType.getIntOrFloatBitWidth();
    46→  }
    47→  int64_t size = std::accumulate(shape.begin(), shape.end(), elemBitWidth,
    48→                                 std::multiplies<int64_t>{});
    49→  constexpr int64_t kBitsInByte = 8;
    50→  size = llvm::divideCeil(size, kBitsInByte);
    51→  return size;
    52→}
    53→
    54→void LLVMCPUVerifyVectorSizeLegalityPass::runOnOperation() {
    55→  FunctionOpInterface funcOp = getOperation();
    56→  // Use 64 bits as target hardware vector size if the native_vector_size is not
    57→  // present.
    58→  int64_t maxVectorSizeInBytes = 8;
    59→  auto targetAttr = IREE::HAL::ExecutableTargetAttr::lookup(funcOp);
    60→  if (targetAttr) {
    61→    auto nativeVectorSizeAttr =
    62→        getConfigIntegerAttr(targetAttr, "native_vector_size");
    63→    if (nativeVectorSizeAttr) {
    64→      maxVectorSizeInBytes = nativeVectorSizeAttr->getInt();
    65→    }
    66→  }
    67→  constexpr int64_t kInt64Max = std::numeric_limits<int64_t>::max();
    68→  if (maxVectorSizeInBytes >
    69→      kInt64Max / this->maxAllowedNumberOfNativeVectors) {
    70→    funcOp.emitError("The value of maxAllowedNumberOfNativeVectors is too "
    71→                     "large, which causes integer overflow. Is it a bug?");
    72→    return signalPassFailure();
    73→  }
    74→  maxVectorSizeInBytes *= this->maxAllowedNumberOfNativeVectors;
    75→
    76→  auto checkFn = [&](Type t) {
    77→    auto vectorType = dyn_cast<VectorType>(t);
    78→    if (!vectorType) {
    79→      return false;
    80→    }
    81→    int64_t size =
    82→        getTotalSizeInBytes(vectorType.getElementType(), vectorType.getShape());
    83→    return size >= maxVectorSizeInBytes;
    84→  };
    85→  auto isLargeVectorContract = [&](vector::ContractionOp op) {
    86→    SmallVector<int64_t> iterationBounds;
    87→    op.getIterationBounds(iterationBounds);
    88→    int64_t size = getTotalSizeInBytes(getElementTypeOrSelf(op.getAccType()),
    89→                                       iterationBounds);
    90→    return size >= maxVectorSizeInBytes;
    91→  };
    92→
    93→  SmallVector<Operation *> invalidOps;
    94→  funcOp.walk([&](Operation *op) {
    95→    auto contractOp = dyn_cast<vector::ContractionOp>(op);
    96→    if (contractOp && isLargeVectorContract(contractOp)) {
    97→      invalidOps.push_back(op);
    98→      return;
    99→    }
   100→
   101→    SmallVector<Type> types(op->getOperandTypes());
   102→    llvm::append_range(types, op->getResultTypes());
   103→    if (llvm::any_of(types, checkFn)) {
   104→      invalidOps.push_back(op);
   105→    }
   106→  });
   107→  if (invalidOps.empty()) {
   108→    return;
   109→  }
   110→
   111→  // Error fall-through. Attach all reported issues as notes.
   112→  InFlightDiagnostic errorDiag =
   113→      emitError(funcOp.getLoc())
   114→      << "One or more operations with large vector sizes ("
   115→      << maxVectorSizeInBytes << " bytes) were found:\n";
   116→  for (Operation *op : invalidOps) {
   117→    errorDiag.attachNote(op->getLoc()) << "  " << *op << "\n";
   118→  }
   119→
   120→  signalPassFailure();
   121→}
   122→
   123→std::unique_ptr<InterfacePass<FunctionOpInterface>>
   124→createLLVMCPUVerifyVectorSizeLegalityPass(int64_t ratio) {
   125→  return std::make_unique<LLVMCPUVerifyVectorSizeLegalityPass>(ratio);
   126→}
   127→
   128→} // namespace mlir::iree_compiler
