    25→/// Selects the lowering strategy for a hal.executable.variant operation.
    26→class LLVMCPUSelectLoweringStrategyPass
    27→    : public impl::LLVMCPUSelectLoweringStrategyPassBase<
    28→          LLVMCPUSelectLoweringStrategyPass> {
    29→public:
    30→  void getDependentDialects(DialectRegistry &registry) const override {
