   313→/// For a given `shapedType` or (`byteWidth` of element type) return the number
   314→/// of elements that correspond to the native vector size. Returns 1 as the
   315→/// fallback.
   316→static int64_t getVectorSize(mlir::FunctionOpInterface entryPointFn,
   317→                             unsigned byteWidth) {
   318→  return getNativeVectorSizeInBytes(entryPointFn) / byteWidth;
   319→}
   320→static int64_t getVectorSize(mlir::FunctionOpInterface entryPointFn,
   321→                             ShapedType shapedType) {
   322→  Type elementType = shapedType.getElementType();
   323→  if (!elementType.isIntOrFloat())
   324→    return 1;
   325→  unsigned byteWidth = IREE::Util::getRoundedElementByteWidth(elementType);
   326→  return getVectorSize(entryPointFn, byteWidth);
   327→}
   328→
   329→/// Returns true if the operation is a GenericOp implementing a supported
   330→/// transposition:
   331→///   1. The op has a single input and a single output.
   332→///   2. One of the indexing_map is identity and the other is a permutation.
   333→static bool x86TransposeLoweringPrecondition(linalg::GenericOp genericOp) {
   334→  // Check that the op has at least 2 dimensions.
   335→  if (genericOp.getNumLoops() < 2) {
   336→    return false;
   337→  }
   338→
   339→  // Check that the op has only one input and one output.
   340→  // TODO(diegocaballero): Generalize to multiple inputs.
   341→  if ((genericOp.getNumDpsInputs() != 1) || (genericOp.getNumDpsInits() != 1)) {
   342→    return false;
   343→  }
   344→
   345→  // Check that all the iterators are parallel.
   346→  if (genericOp.getNumParallelLoops() != genericOp.getNumLoops()) {
   347→    return false;
   348→  }
   349→
   350→  // Check that the two indexing maps are a permutation of each other.
   351→  auto indexingMaps = genericOp.getIndexingMapsArray();
   352→  return !indexingMaps[0].isEmpty() && !indexingMaps[1].isEmpty() &&
   353→         ((indexingMaps[0].isIdentity() && !indexingMaps[1].isIdentity() &&
   354→           indexingMaps[1].isPermutation()) ||
   355→          (!indexingMaps[0].isIdentity() && indexingMaps[0].isPermutation() &&
   356→           indexingMaps[1].isIdentity()));
   357→}
   358→
   359→/// Returns minimum tiling sizes for each dimension. One dimension is possible
   360→/// to access at different element types. It determines the tiling sizes by
   361→/// looking into all the operands.
   362→// TODO(diegocaballero): Refactor this logic to a method that computes the final
   363→// tile sizes for vectorization/unrolling in one shot.
   364→static SmallVector<int64_t>
   365→getMinTilingSizesForEachDim(mlir::FunctionOpInterface entryPointFn,
   366→                            linalg::LinalgOp op,
   367→                            const LinalgOpInfo &linalgOpInfo,
   368→                            const TargetMLTransformInfo &targetMLTransInfo) {
   369→  unsigned numLoops = op.getNumLoops();
   370→  SmallVector<int64_t> minTileSizes(numLoops, 1);
   371→  auto inputOutputOpOperands = op->getOpOperands();
   372→
   373→  for (auto [index, map] : llvm::enumerate(op.getIndexingMapsArray())) {
   374→    // Check the fastest varying dimension of the operand. Set the vector size
   375→    // of the corresponding loop to the vector size.
   376→    if (map.getNumResults() == 0)
   377→      continue;
   378→    auto fastestVaryingDimExpr =
   379→        dyn_cast<AffineDimExpr>(map.getResults().back());
   380→    if (!fastestVaryingDimExpr)
   381→      continue;
   382→    unsigned fastestVaryingDim = fastestVaryingDimExpr.getPosition();
   383→
   384→    // If the indexing map has result it has to be a shaped type.
   385→    auto operandType =
   386→        llvm::cast<ShapedType>(inputOutputOpOperands[index].get().getType());
   387→    int64_t tileSize = getVectorSize(entryPointFn, operandType);
   388→
   389→    minTileSizes[fastestVaryingDim] =
   390→        std::max<int64_t>(minTileSizes[fastestVaryingDim], tileSize);
   391→  }
   392→
   393→  // Limit unroll factor. For now, we assume the rightmost non-one tiled
   394→  // dimension is for vectorization and any other non-one dimension is for
   395→  // unrolling. The util limits the second rightmost non-one tiled dimension
   396→  // to be not larger than `maxUnrollFactor` and others tiled dimension to 1.
   397→  auto limitUnrollFactor = [&](int64_t maxUnrollFactor) {
   398→    int vecDim;
   399→    for (vecDim = minTileSizes.size() - 1; vecDim >= 0; --vecDim) {
   400→      if (minTileSizes[vecDim] > 1) {
   401→        break;
   402→      }
   403→    }
   404→    bool seen = false;
   405→    for (int unrollDim = vecDim - 1; unrollDim >= 0; --unrollDim) {
   406→      if (minTileSizes[unrollDim] <= 1) {
   407→        continue;
   408→      }
   409→      int64_t factor = seen ? 1LL : maxUnrollFactor;
   410→      seen = true;
   411→      LLVM_DEBUG(KD_DBGS() << "Adjusted min tile sizes: "
   412→                           << minTileSizes[unrollDim]
   413→                           << " with factor=" << factor << "\n");
   414→      minTileSizes[unrollDim] =
   415→          std::min<int64_t>(minTileSizes[unrollDim], factor);
   416→    }
   417→  };
   418→
   419→  auto genericOp = dyn_cast<linalg::GenericOp>(op.getOperation());
   420→  if (linalgOpInfo.isTranspose() && genericOp &&
   421→      x86TransposeLoweringPrecondition(genericOp)) {
   422→    // TODO(dcaballe): Consider input and output transposes.
   423→    limitUnrollFactor(targetMLTransInfo.defaultMaxTransposeUnrollFactor);
   424→  } else if (linalgOpInfo.isReduction()) {
   425→    limitUnrollFactor(targetMLTransInfo.defaultMaxReductionUnrollFactor);
   426→  } else {
   427→    limitUnrollFactor(targetMLTransInfo.defaultMaxElementwiseUnrollFactor);
   428→  }
   429→
   430→  return minTileSizes;
   431→}
