   433→// Reduces the number of workgroups in cases where we are dividing the work too
   434→// much. Over-provision the number of workgroups to twice the number of
   435→// threads.
   436→static void reduceDistributionWorkgroups(
   437→    ArrayRef<int64_t> workload, SmallVectorImpl<int64_t> &distributedTileSizes,
   438→    std::optional<ArrayRef<int64_t>> maxTileSizes = std::nullopt,
   439→    std::optional<ArrayRef<int64_t>> vectorSizeHints = std::nullopt) {
   440→  assert(workload.size() == distributedTileSizes.size());
   441→  SmallVector<int64_t> numWorkgroupsPerDim(workload.size(), 1);
   442→  for (auto [idx, value] : llvm::enumerate(workload)) {
   443→    if (distributedTileSizes[idx] == 0 || ShapedType::isDynamic(value)) {
   444→      continue;
   445→    }
   446→    numWorkgroupsPerDim[idx] =
   447→        llvm::divideCeil(value, distributedTileSizes[idx]);
   448→  }
   449→
   450→  int64_t numWorkgroupsLimit = 2 * clNumberOfRuntimeThreads;
   451→  int64_t numWorkgroups =
   452→      std::accumulate(numWorkgroupsPerDim.begin(), numWorkgroupsPerDim.end(),
   453→                      1LL, std::multiplies<int64_t>{});
   454→  unsigned currDim = workload.size();
   455→  while (numWorkgroups > numWorkgroupsLimit && currDim > 0) {
   456→    unsigned index = currDim - 1;
   457→    int64_t currSize = distributedTileSizes[index];
   458→    if (ShapedType::isDynamic(workload[index]) || currSize == 0 ||
   459→        (maxTileSizes && currSize >= maxTileSizes.value()[index]) ||
   460→        currSize >= workload[index]) {
   461→      currDim--;
   462→      continue;
   463→    }
   464→
   465→    int64_t newSize = std::min<int64_t>(currSize * 2, workload[index]);
   466→    int64_t vectorSize = vectorSizeHints ? vectorSizeHints.value()[index] : 0;
   467→
   468→    // Chech if it's the ideal size with vector size hint. And skip if the new
   469→    // size will break the ideal size.
   470→    if (vectorSize > 1 &&
   471→        (currSize % vectorSize == 0 && workload[index] % currSize == 0) &&
   472→        (newSize % vectorSize != 0 || workload[index] % newSize != 0)) {
   473→      currDim--;
   474→      continue;
   475→    }
   476→
   477→    distributedTileSizes[index] = newSize;
   478→    int64_t nwg =
   479→        llvm::divideCeil(workload[index], distributedTileSizes[index]);
   480→    if (nwg < numWorkgroupsPerDim[index]) {
   481→      numWorkgroups /= numWorkgroupsPerDim[index];
   482→      numWorkgroupsPerDim[index] = nwg;
   483→      numWorkgroups *= nwg;
   484→    } else {
   485→      currDim--;
   486→    }
   487→  }
   488→
   489→  // Final fixup for dividing workload evenly.
   490→  for (auto i : llvm::seq<unsigned>(0, distributedTileSizes.size())) {
   491→    if (distributedTileSizes[i] == 0 || ShapedType::isDynamic(workload[i])) {
   492→      continue;
   493→    }
   494→
   495→    int64_t nwg = llvm::divideCeil(workload[i], distributedTileSizes[i]);
   496→    int64_t newSize = llvm::divideCeil(workload[i], nwg);
   497→
   498→    // Chech if it's the ideal size with vector size hint. And skip if the new
   499→    // size will break the ideal size.
   500→    int64_t vectorSize = vectorSizeHints ? vectorSizeHints.value()[i] : 0;
   501→    if (vectorSize > 1 &&
   502→        (newSize % vectorSize != 0 || workload[i] % newSize != 0)) {
   503→      continue;
   504→    }
   505→
   506→    distributedTileSizes[i] = newSize;
   507→  }
   508→}
