   510→/// Returns the default tile sizes to use for the loops that are distributed.
   511→static SmallVector<int64_t>
   512→getDefaultDistributionTileSizes(ArrayRef<int64_t> lbs, ArrayRef<int64_t> ubs,
   513→                                ArrayRef<int64_t> minTileSizes,
   514→                                ArrayRef<int64_t> maxTileSizes,
   515→                                ArrayRef<int64_t> vectorSizeHints) {
   516→  assert(lbs.size() == ubs.size() && lbs.size() == minTileSizes.size() &&
   517→         lbs.size() == maxTileSizes.size() &&
   518→         "expected all vectors to be of equal size");
   519→
   520→  size_t numDims = lbs.size();
   521→  // Set all the distribution tile sizes to zero if thread distribution is
   522→  // disabled.
   523→  if (clDisableDistribution) {
   524→    return SmallVector<int64_t>(numDims, 0);
   525→  }
   526→
   527→  SmallVector<int64_t> distributedTileSizes(numDims, 1);
   528→  SmallVector<int64_t> workload(numDims, 1);
   529→  for (auto i : llvm::seq<size_t>(0, numDims)) {
   530→    if (maxTileSizes[i] == 0 || ShapedType::isDynamic(lbs[i]) ||
   531→        ShapedType::isDynamic(ubs[i])) {
   532→      distributedTileSizes[i] = maxTileSizes[i];
   533→      workload[i] = ShapedType::kDynamic;
   534→      continue;
   535→    }
   536→
   537→    assert(lbs[i] <= ubs[i]);
   538→    workload[i] = ubs[i] - lbs[i];
   539→    int64_t candidateTileSize = 1;
   540→    int64_t targetSize =
   541→        std::min(workload[i] / clNumberOfRuntimeThreads, maxTileSizes[i]);
   542→    int64_t vectorSize = vectorSizeHints[i];
   543→    if (vectorSize > 1) {
   544→      // Pick the factor of dim which is closest to the target tile size and
   545→      // is a multiplier of vector size.
   546→      for (int64_t k = vectorSize; k <= targetSize; k += vectorSize) {
   547→        if (workload[i] % k == 0 && k >= minTileSizes[i]) {
   548→          candidateTileSize = k;
   549→        }
   550→      }
   551→    }
   552→    // Fallback to power of 2 if there's no hint or can't find the ideal size.
   553→    if (vectorSize <= 1 || candidateTileSize == 1) {
   554→      candidateTileSize = std::max<int64_t>(
   555→          llvm::bit_floor<uint64_t>(targetSize), minTileSizes[i]);
   556→    }
   557→
   558→    // Limit the workload per workgroup to the default being the max to keep the
   559→    // work per invocation reasonable.
   560→    distributedTileSizes[i] =
   561→        std::min<int64_t>(candidateTileSize, maxTileSizes[i]);
   562→  }
   563→
   564→  reduceDistributionWorkgroups(workload, distributedTileSizes, maxTileSizes,
   565→                               vectorSizeHints);
   566→
   567→  return distributedTileSizes;
   568→}
