   570→/// Returns the nearest power of two of `size` if `predicate` is true.
   571→/// Otherwise, returns `size`.
   572→static int64_t roundUpToPow2(int64_t size, bool predicate) {
   573→  if (!predicate) {
   574→    return size;
   575→  }
   576→  assert(size > 0 && "Negative size");
   577→  return llvm::PowerOf2Ceil(size);
   578→}
