   580→/// Computes the maximum tile size that can be used to distribute a dimension
   581→/// based on its number of iterations and the native vector size used of the
   582→/// target. The resulting tile size will be a multiple of the provided vector
   583→/// size, except when `allowIncompleteTile` is set to true.
   584→static int64_t getMaxDistributionTileSize(int64_t lb, int64_t ub,
   585→                                          int64_t maxSize, int64_t vectorSize,
   586→                                          bool allowIncompleteTile = false) {
   587→  if (ShapedType::isDynamic(ub) || ShapedType::isDynamic(lb)) {
   588→    return maxSize;
   589→  }
   590→  int64_t numIters = ub - lb;
   591→  if (numIters <= maxSize && numIters < vectorSize) {
   592→    return numIters;
   593→  }
   594→
   595→  int64_t scaledUB = std::min(maxSize, numIters) / vectorSize * vectorSize;
   596→  for (int64_t i = scaledUB; i > 0; i -= vectorSize) {
   597→    if (numIters % i == 0) {
   598→      return i;
   599→    }

