   793→// Returns the size in bits of SIMD register space, or 0 if it can't be
   794→// determined (e.g. Arm SVE).
   795→static int getRegisterSpaceBitsIfKnown(IREE::HAL::ExecutableTargetAttr target) {
   796→  if (isX86(target)) {
   797→    if (hasFeature(target, "+avx512f")) {
   798→      return 32 * 512;
   799→    } else if (hasFeature(target, "+avx") || hasFeature(target, "+avx2")) {
   800→      return 16 * 256;
   801→    } else {
   802→      return 16 * 128;
   803→    }
   804→  } else if (isAArch64(target)) {
   805→    // 32 NEON/SVE registers (at least 128-bit each, returns the base size for
   806→    // SVE).
   807→    return 32 * 128;
   808→  } else {
   809→    // Don't know register space size as a compile-time constant on other
   810→    // architectures.
   811→    return 0;
   812→  }
   813→}
   814→
   815→// Clamps in-place vecTileSizes to ensure that the tile sizes of all operands of
   816→// `op` can simultaneously be allocated in SIMD registers. Does nothing when
   817→// SIMD register space can't be determined as a compile-time constant (e.g. Arm
   818→// SVE).
   819→static void limitVectorTileSizes(linalg::LinalgOp op,
   820→                                 SmallVectorImpl<int64_t> &vecTileSizes) {
   821→  if (int registerSpaceBits = getRegisterSpaceBitsIfKnown(
   822→          IREE::HAL::ExecutableTargetAttr::lookup(op))) {
   823→    limitVectorTileSizes(op, vecTileSizes, registerSpaceBits,
   824→                         registerSpaceBits);
   825→  }
   826→}
