   828→/// Struct that holds factors for heuristic distribution tile sizes selection.
   829→/// The `minTileSizes`, `maxTileSizes` and `vectorSizeHints` can be empty or
   830→/// as many as the number of loops.
   831→struct DistributionHeuristicConfig {
   832→  // TODO(hanchung): Remove `allowIncompleteTile` option after codegen can
   833→  // vectorize all the shapes. Allowing incomplete tile is critical for odd
   834→  // shapes (e.g., some dim sizes could be prime number).
   835→  bool allowIncompleteTile = false;
   836→
   837→  SmallVector<int64_t> minTileSizes;
   838→  SmallVector<int64_t> maxTileSizes;
   839→
   840→  // On the dimensions where the hints != 1, it will try to find the tile sizes
   841→  // which are multipliers of the hints.
   842→  SmallVector<int64_t> vectorSizeHints;
   843→};
   844→
   845→/// Returns the tile size to use for distribution. The `op` needs to be a
   846→/// TilingInterface op.
   847→static SmallVector<int64_t>
   848→getDefaultDistributedLevelTileSizes(Operation *op,
   849→                                    const DistributionHeuristicConfig &config) {
   850→  SmallVector<int64_t> lbs, ubs;
   851→  getRangeBounds(cast<TilingInterface>(op), lbs, ubs);
   852→  int64_t numLoops = lbs.size();
   853→
   854→  assert(
   855→      (config.minTileSizes.empty() || config.minTileSizes.size() == numLoops) &&
   856→      "min tile sizes should be empty or equal to the number of loops");
   857→  assert(
   858→      (config.maxTileSizes.empty() || config.maxTileSizes.size() == numLoops) &&
   859→      "max tile sizes should be empty or equal to the number of loops");
   860→  assert((config.vectorSizeHints.empty() ||
   861→          config.vectorSizeHints.size() == numLoops) &&
   862→         "vector size hints should be empty or equal to the number of loops");
   863→
   864→  // Only set values when the loop is partitionable.
   865→  SmallVector<int64_t> adjustedMinTileSizes(numLoops, 0);
   866→  SmallVector<int64_t> adjustedMaxTileSizes(numLoops, 0);
   867→  SmallVector<int64_t> adjustedVectorSizeHints(numLoops, 1);
   868→  SmallVector<unsigned> partitionableLoops =
   869→      cast<PartitionableLoopsInterface>(op).getPartitionableLoops(std::nullopt);
   870→  for (auto i : partitionableLoops) {
   871→    adjustedMinTileSizes[i] =
   872→        config.minTileSizes.empty() ? 1 : config.minTileSizes[i];
   873→    adjustedMaxTileSizes[i] = config.maxTileSizes.empty()
   874→                                  ? clDefaultDistTileSize
   875→                                  : config.maxTileSizes[i];
   876→    adjustedVectorSizeHints[i] =
   877→        config.vectorSizeHints.empty() ? 1 : config.vectorSizeHints[i];
   878→  }
   879→
   880→  LLVM_DEBUG(KD_DBGS() << "Adjusted min tile sizes: " << adjustedMinTileSizes
   881→                       << "\n");
   882→  LLVM_DEBUG(KD_DBGS() << "Adjusted max tile sizes: " << adjustedMaxTileSizes
   883→                       << "\n");
   884→  LLVM_DEBUG(KD_DBGS() << "Adjusted vector size hints: "
   885→                       << adjustedVectorSizeHints << "\n");
   886→
   887→  SmallVector<int64_t> distributedTileSizes = getDefaultDistributionTileSizes(
   888→      lbs, ubs, adjustedMinTileSizes, adjustedMaxTileSizes,
   889→      adjustedVectorSizeHints);
   890→
   891→  LLVM_DEBUG(KD_DBGS() << "Distributed tile sizes before fixups: "
   892→                       << distributedTileSizes << "\n");
   893→
   894→  // Final fix up of the tile sizes to make sure that they divide the problem
   895→  // size to make it vectorizable.
   896→  for (auto i : llvm::seq<unsigned>(0, distributedTileSizes.size())) {
   897→    if (!distributedTileSizes[i])
   898→      continue;
   899→    distributedTileSizes[i] = getMaxDistributionTileSize(
   900→        lbs[i], ubs[i], distributedTileSizes[i], adjustedMinTileSizes[i],
   901→        config.allowIncompleteTile);
   902→  }
   903→  LLVM_DEBUG(KD_DBGS() << "Distributed tile sizes after fixups: "
   904→                       << distributedTileSizes << "\n");
   905→  return distributedTileSizes;
   906→}
