   908→/// Splits the tile sizes in `parallelSizes` into `reductionSizes` for the
   909→/// reduction loops.
   910→static void splitParallelAndReductionTiles(
   911→    Operation *op, SmallVectorImpl<int64_t> &parallelSizes,
   912→    SmallVectorImpl<int64_t> &reductionSizes,
   913→    SmallVectorImpl<bool> *parallelScalableFlags = nullptr,
   914→    SmallVectorImpl<bool> *reductionScalableFlags = nullptr) {
   915→  reductionSizes.assign(parallelSizes.begin(), parallelSizes.end());
   916→  if (reductionScalableFlags) {
   917→    assert(parallelScalableFlags && "expected parallel scalable flags!");
   918→    reductionScalableFlags->assign(parallelScalableFlags->begin(),
   919→                                   parallelScalableFlags->end());
   920→  }
   921→  TilingInterface tilingOp = cast<TilingInterface>(op);
   922→  for (auto [index, iteratorType] :
   923→       llvm::enumerate(tilingOp.getLoopIteratorTypes())) {
   924→    if (iteratorType == utils::IteratorType::parallel) {
   925→      reductionSizes[index] = 0;
   926→      if (reductionScalableFlags)
   927→        (*reductionScalableFlags)[index] = false;
   928→    } else {
   929→      parallelSizes[index] = 0;
   930→      if (parallelScalableFlags)
   931→        (*parallelScalableFlags)[index] = false;
   932→    }
   933→  }
   934→}
