   936→static void setAlwaysVectorizeSizes(linalg::LinalgOp op,
   937→                                    SmallVectorImpl<int64_t> &parallelSizes,
   938→                                    SmallVectorImpl<int64_t> &reductionSizes) {
   939→  SmallVector<int64_t> staticLoopRanges = op.getStaticLoopRanges();
   940→  for (auto [index, valuePair] : llvm::enumerate(
   941→           llvm::zip_equal(staticLoopRanges, op.getIteratorTypesArray()))) {
   942→    auto [size, iterType] = valuePair;
   943→    if (!ShapedType::isDynamic(size))
   944→      continue;
   945→    if (iterType == utils::IteratorType::parallel) {
   946→      parallelSizes[index] = 1;
   947→    } else {
   948→      reductionSizes[index] = 1;
   949→    }
   950→  }
   951→
   952→  LLVM_DEBUG(KD_DBGS() << "Set always-vectorize parallel sizes: "
   953→                       << parallelSizes << "\n");
   954→  LLVM_DEBUG(KD_DBGS() << "Set always-vectorize reduction sizes: "
   955→                       << reductionSizes << "\n");
   956→}
   957→
   958→static void
   959→setVectorSizesForDynamicShapes(linalg::LinalgOp op,
   960→                               VectorPreProcStrategy vecPreProcStrategy,
   961→                               SmallVectorImpl<int64_t> &parallelSizes,
   962→                               SmallVectorImpl<int64_t> &reductionSizes) {
   963→  // Masking doesn't need any dim set to 1.
   964→  if (vecPreProcStrategy == VectorPreProcStrategy::Masking) {
   965→    return;
   966→  }
   967→
